**Working directory:** C:\Users\User\loyalty-app

**What to do:**

1. **Modify `apps/dashboard/src/components/campaign-form.tsx`** — Add a segment selector dropdown with options: `all`, `new` (joined < 30 days), `inactive` (no activity > 14 days), `vip` (gold/vip tier). Save it as `target_segment` when creating the campaign. Update the button text to reflect the selected segment.

Current content of `apps/dashboard/src/components/campaign-form.tsx`:
```tsx
'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';

export function CampaignForm({ merchantId }: { merchantId: string }) {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleSend(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);

    const { data: campaign, error } = await supabase.from('campaigns').insert({
      merchant_id: merchantId,
      title,
      body,
      type: 'push',
      target_segment: 'all',
      status: 'draft',
    }).select().single();

    if (error || !campaign) { setLoading(false); return; }

    await supabase.functions.invoke('send-push', { body: { campaign_id: campaign.id } });

    setTitle('');
    setBody('');
    setLoading(false);
    router.refresh();
  }

  return (
    <form onSubmit={handleSend} className="space-y-4 max-w-lg p-4 border rounded-lg">
      <h3 className="font-semibold">Send Push Notification</h3>
      <div><Label>Title</Label><Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. Weekend Special!" required /></div>
      <div><Label>Message</Label><Textarea value={body} onChange={(e) => setBody(e.target.value)} placeholder="e.g. 20% off all items this weekend!" required /></div>
      <Button type="submit" disabled={loading}>{loading ? 'Sending...' : 'Send to All Clients'}</Button>
    </form>
  );
}
```

2. **Modify `supabase/functions/send-push/index.ts`** — After fetching cards, apply segment filtering based on `campaign.target_segment`:
- `all`: no filter
- `new`: `created_at` within last 30 days
- `inactive`: `last_activity` older than 14 days
- `vip`: tier is 'gold' or 'vip'

Current content of `supabase/functions/send-push/index.ts`:
```typescript
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const { campaign_id } = await req.json();
    if (!campaign_id) return new Response(JSON.stringify({ error: 'Missing campaign_id' }), { status: 400, headers: corsHeaders });

    const { data: campaign } = await supabase.from('campaigns').select('*').eq('id', campaign_id).single();
    if (!campaign) return new Response(JSON.stringify({ error: 'Campaign not found' }), { status: 404, headers: corsHeaders });

    const { data: cards } = await supabase
      .from('customer_cards')
      .select('customer_id, customers(push_token), loyalty_programs!inner(merchant_id)')
      .eq('loyalty_programs.merchant_id', campaign.merchant_id);

    const tokens = cards
      ?.map((c: any) => c.customers?.push_token)
      .filter(Boolean) as string[];

    if (!tokens.length) {
      return new Response(JSON.stringify({ sent: 0 }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    const messages = tokens.map((token) => ({
      to: token,
      title: campaign.title,
      body: campaign.body,
      data: { campaign_id: campaign.id, type: 'campaign' },
    }));

    await fetch('https://exp.host/--/api/v2/push/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(messages),
    });

    const notifications = cards?.map((c: any) => ({
      customer_id: c.customer_id,
      campaign_id: campaign.id,
      title: campaign.title,
      body: campaign.body,
      type: 'campaign' as const,
    })) ?? [];

    if (notifications.length) {
      await supabase.from('notifications').insert(notifications);
    }

    await supabase.from('campaigns').update({
      status: 'sent',
      sent_at: new Date().toISOString(),
    }).eq('id', campaign.id);

    return new Response(JSON.stringify({ sent: tokens.length }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });

  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});
```

3. **Commit** with message: `feat: add customer segmentation to campaigns`

**Important:**
- Use the shadcn/ui Select component. The dashboard uses shadcn/ui. Check if Select is already installed, if not use a native HTML `<select>` element styled with Tailwind.
- In the send-push function, also fetch `created_at`, `last_activity`, and `tier` fields from `customer_cards` so the segment filter can work.
- The select query needs to include those fields: `customer_id, created_at, last_activity, tier, customers(push_token), loyalty_programs!inner(merchant_id)`
- After filtering, extract tokens from the filtered set and also only create notifications for the filtered cards.
- Do NOT skip committing.

