'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

type Segment = 'all' | 'new' | 'inactive' | 'vip';

const SEGMENT_LABELS: Record<Segment, string> = {
  all: 'All Clients',
  new: 'New Clients (joined < 30 days)',
  inactive: 'Inactive Clients (no activity > 14 days)',
  vip: 'VIP Clients (Gold / VIP tier)',
};

const SEGMENT_BUTTON_LABELS: Record<Segment, string> = {
  all: 'Send to All Clients',
  new: 'Send to New Clients',
  inactive: 'Send to Inactive Clients',
  vip: 'Send to VIP Clients',
};

export function CampaignForm({ merchantId }: { merchantId: string }) {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [segment, setSegment] = useState<Segment>('all');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleSend(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);

    const { data: campaign, error } = await supabase.from('campaigns').insert({
      merchant_id: merchantId,
      title,
      body,
      type: 'push',
      target_segment: segment,
      status: 'draft',
    }).select().single();

    if (error || !campaign) { setLoading(false); return; }

    await supabase.functions.invoke('send-push', { body: { campaign_id: campaign.id } });

    setTitle('');
    setBody('');
    setSegment('all');
    setLoading(false);
    router.refresh();
  }

  return (
    <form onSubmit={handleSend} className="space-y-4 max-w-lg p-4 border rounded-lg">
      <h3 className="font-semibold">Send Push Notification</h3>
      <div><Label>Title</Label><Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. Weekend Special!" required /></div>
      <div><Label>Message</Label><Textarea value={body} onChange={(e) => setBody(e.target.value)} placeholder="e.g. 20% off all items this weekend!" required /></div>
      <div>
        <Label>Target Segment</Label>
        <Select value={segment} onValueChange={(value) => setSegment(value as Segment)}>
          <SelectTrigger className="w-full">
            <SelectValue placeholder="Select a segment" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{SEGMENT_LABELS.all}</SelectItem>
            <SelectItem value="new">{SEGMENT_LABELS.new}</SelectItem>
            <SelectItem value="inactive">{SEGMENT_LABELS.inactive}</SelectItem>
            <SelectItem value="vip">{SEGMENT_LABELS.vip}</SelectItem>
          </SelectContent>
        </Select>
      </div>
      <Button type="submit" disabled={loading}>{loading ? 'Sending...' : SEGMENT_BUTTON_LABELS[segment]}</Button>
    </form>
  );
}

