      return daysSinceCreation <= 30;
    }
    case 'inactive': {
      if (!c.last_activity) return true; // no activity at all counts as inactive
      const lastActivity = new Date(c.last_activity);
      const daysSinceActivity = (now.getTime() - lastActivity.getTime()) / (1000 * 60 * 60 * 24);
      return daysSinceActivity > 14;
    }
    case 'vip': {
      const tier = (c.tier ?? '').toLowerCase();
      return tier === 'gold' || tier === 'vip';
    }
    case 'all':
    default:
      return true;
  }
});

